import{r as a,o as r,c as o,a as e,e as i,w as d,F as h,g as t,k as m}from"./app.0f23220d.js";import{_ as u}from"./plugin-vue_export-helper.21dcd24c.js";const c={},g=t("\u{1F519} Back to "),p=e("strong",null,"Projects",-1),f=e("h1",{id:"flags-n-machines",tabindex:"-1"},[e("a",{class:"header-anchor",href:"#flags-n-machines","aria-hidden":"true"},"#"),t(" Flags'n'Machines")],-1),_=m('<h2 id="summary" tabindex="-1"><a class="header-anchor" href="#summary" aria-hidden="true">#</a> Summary</h2><p>One of my most ambitious games, <strong>Flags&#39;n&#39;Machines</strong>, is an open-source 3D multiplayer CTF driving game (yes, flags and cars, hence the game name).</p><p>That&#39;s the game that made me start <a href="../game-related/my-godot-plugins">Godot plugin projects</a>.</p><h2 id="design-document" tabindex="-1"><a class="header-anchor" href="#design-document" aria-hidden="true">#</a> Design document</h2><h3 id="aesthetics" tabindex="-1"><a class="header-anchor" href="#aesthetics" aria-hidden="true">#</a> Aesthetics</h3><ul><li>Racing game at third-person or first-person view, in a &quot;small world&quot; concept (like Micro Machines).</li><li>Really simple graphics, should run on most computers (and should be mobile and web friendly).</li></ul><h3 id="gameplay" tabindex="-1"><a class="header-anchor" href="#gameplay" aria-hidden="true">#</a> Gameplay</h3><ul><li>CTF game mixed with elimination mode, based on time limit and rounds</li><li>A round starts with everyone on the map, until only one person remains on the map <ul><li>If someone falls, he lost one point for autodestruction (-1)</li><li>If someone falls because he was pushed by someone else, he doesn&#39;t lose points, but the attacker wins 1 point.</li><li>There is a flag on the map, with a green zone around. It is quite large at the beginning, but when the flag is taken, the zone become smaller and smaller. When the flag is taken, the zone turns red, and players outside the zone are in &quot;danger mode&quot;. Danger mode destroy cars outside the flag zone after some delimited time. When the flag is small enough (size of the car), the carrier automatically wins, and he wins 5 points.</li><li>When someone dies, he can&#39;t join back in the game until the next round.</li></ul></li><li>The gravity is altered in the game, with magnet like movements: if a car jumps or drive towards a wall, the car &quot;snaps&quot; at the wall.</li><li>If you run into the flag carrier, you take the flag</li></ul><h3 id="abilities" tabindex="-1"><a class="header-anchor" href="#abilities" aria-hidden="true">#</a> Abilities</h3><ul><li>Cars can jump</li><li>Items can make you fire lasers or dash quickly in a direction</li><li>Items spaws at item spawn point (like Quake or Unreal)</li></ul><h3 id="game-start" tabindex="-1"><a class="header-anchor" href="#game-start" aria-hidden="true">#</a> Game start</h3><ul><li>Multiplayer is not lobby based but round based.</li><li>If you are alone in the level, no flag will appear, and you will autorespawn if you fall.</li><li>At level initialization (alone in map), you need to wait a little before the round starts (game wait time). If the time expires and you are still alone, it restarts.</li><li>If max players are present, the game autostarts.</li><li>The admin can start the game at any moment.</li><li>You can add bots in a game.</li><li>Spectator mode, where you can follow another car or move freely on the map.</li></ul><h3 id="technical" tabindex="-1"><a class="header-anchor" href="#technical" aria-hidden="true">#</a> Technical</h3><ul><li>Cvars: game is based on cvars and commands <ul><li>Vars: <ul><li>max_players</li><li>round_time</li><li>game_time</li><li>game_init_wait_time</li><li>world_gravity</li><li>cars_drive_speed</li><li>cars_jump_speed</li><li>danger_mode_duration</li></ul></li><li>Commands <ul><li>restart_game</li><li>restart_round</li><li>kill</li><li>bot_add</li><li>bot_kick</li></ul></li></ul></li><li>Separate game logic from networking, using adapters</li></ul>',14);function y(l,b){const n=a("RouterLink"),s=a("ProjectCard");return r(),o(h,null,[e("p",null,[i(n,{to:"/projects/"},{default:d(()=>[g,p]),_:1})]),f,e("p",null,[i(s,{language:"Godot/C#",date:"2021",status:"paused",url:"https://github.com/Srynetix/flags-n-machines",screenshot:l.$withBase("/images/flags-n-machines.gif")},null,8,["screenshot"])]),_],64)}var x=u(c,[["render",y]]);export{x as default};
